class Solution:
    def numDistinct(self, s, t):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(1 << 20)
        @lru_cache(None)
        def rec(i, j):
            if j == len(t):
                return 1
            if i == len(s):
                return 0
            total = rec(i + 1, j)
            if s[i] == t[j]:
                total += rec(i + 1, j + 1)
            return total
        return rec(0, 0)

