var numDistinct = function(s, t) {
    const m = t.length;
    const dp = new Array(m + 1).fill(0);
    dp[0] = 1;
    for (const ch of s) {
        for (let j = m; j >= 1; j--) {
            if (ch === t[j - 1]) dp[j] += dp[j - 1];
        }
    }
    return dp[m];
};
